/// Block device path → Filesystem map, keyed by `/dev/vdaN` names.
/// Rootfs device = `/dev/vda`; first secondary = `/dev/vda2`; etc.
/// Populated once during [`init_filesystems`] and immutable afterwards.
static BLOCK_DEVICE_MAP: Once<BTreeMap<String, Filesystem>> = Once::new();

/// Returns the [`Filesystem`] registered under a block device path.
///
/// Used by `sys_mount` to resolve `/dev/vdaN` sources without opening
/// the device file — the mapping is established at boot by [`init_filesystems`].
pub fn get_blkdev_fs(dev_path: &str) -> Option<Filesystem> {
    BLOCK_DEVICE_MAP.get()?.get(dev_path).cloned()
}

/// Initializes the filesystem subsystem, trying each block device
/// and using the first one that contains a valid rootfs (has /bin/sh).
///
/// Additional block devices are mounted at `/sdcard`, `/sdcard2`, etc.
/// so that test files on a separate sdcard image can be accessed
/// without merging disk images.
pub fn init_filesystems(mut block_devs: AxDeviceContainer<AxBlockDevice>) {
    info!("Initialize filesystem subsystem...");

    let num_devs = block_devs.len();
    if num_devs == 0 {
        panic!("No block device found!");
    }

    info!("  found {} block device(s)", num_devs);

    let mut secondary_fses: alloc::vec::Vec<Filesystem> = alloc::vec::Vec::new();
    let mut rootfs_fs: Option<Filesystem> = None;

    for i in 0..num_devs {
        let dev = block_devs.take_one().unwrap();
        info!("  trying block device {}: {:?}", i, dev.device_name());

        let fs = match fs::new_default(dev) {
            Ok(fs) => fs,
            Err(e) => {
                info!("  failed to init fs: {:?}", e);
                continue;
            }
        };
        info!("  filesystem type: {:?}", fs.name());

        // Check if this device can serve as rootfs (has /bin/sh)
        let mp = axfs_ng_vfs::Mountpoint::new_root(&fs);
        let ctx = FsContext::new(mp.root_location());

        match ctx.resolve("/bin/sh") {
            Ok(_) => {
                if ROOT_FS_CONTEXT.get().is_none() {
                    info!("  found /bin/sh on device {}, using as rootfs", i);
                    rootfs_fs = Some(fs.clone());
                    ROOT_FS_CONTEXT.call_once(|| ctx);
                    continue;
                }
                info!("  device {} also has /bin/sh, mounting as secondary", i);
            }
            Err(e) => {
                info!("  /bin/sh not found on device {} ({:?})", i, e);
            }
        }

        secondary_fses.push(fs);
    }

    if ROOT_FS_CONTEXT.get().is_none() {
        panic!("No block device with /bin/sh found among {} device(s)", num_devs);
    }

    // Build block device name map: rootfs → /dev/vda, secondaries → /dev/vda2, /dev/vda3, ...
    // This naming matches what the basic test suite expects (mount("/dev/vda2", ...)).
    {
        let mut dev_map: BTreeMap<String, Filesystem> = BTreeMap::new();
        if let Some(rfs) = rootfs_fs {
            dev_map.insert(String::from("/dev/vda"), rfs);
        }
        for (idx, sec_fs) in secondary_fses.iter().enumerate() {
            let name = if idx == 0 {
                String::from("/dev/vda2")
            } else {
                alloc::format!("/dev/vda{}", idx + 2)
            };
            dev_map.insert(name, sec_fs.clone());
        }
        BLOCK_DEVICE_MAP.call_once(|| dev_map);
    }

    // Mount secondary filesystems under /s, /s2, etc.
    // Short mount point keeps paths short enough for test binaries with small getcwd buffers.
    let root_ctx = ROOT_FS_CONTEXT.get().unwrap();
    let num_secondary = secondary_fses.len();
    for (idx, sdcard_fs) in secondary_fses.into_iter().enumerate() {
        let mount_path = if idx == 0 {
            alloc::string::String::from("/s")
        } else {
            alloc::format!("/s{}", idx + 1)
        };
        info!("  mounting secondary device at {}", mount_path);

        if root_ctx.resolve(&mount_path).is_err() {
            if let Err(e) = root_ctx.create_dir(
                &mount_path,
                axfs_ng_vfs::NodePermission::from_bits_truncate(0o755),
            ) {
                warn!("  failed to create {}: {:?}", mount_path, e);
                continue;
            }
        }

        match root_ctx.resolve(&mount_path) {
            Ok(loc) => match loc.mount(&sdcard_fs) {
                Ok(_) => info!("  mounted secondary device at {}", mount_path),
                Err(e) => warn!("  failed to mount at {}: {:?}", mount_path, e),
            },
            Err(e) => warn!("  failed to resolve {}: {:?}", mount_path, e),
        }
    }

    info!(
        "Filesystem initialization complete: rootfs + {} secondary device(s)",
        num_secondary
    );
}

